import { useState } from 'react';
import ChatBox from './components/ChatBox';
import IngredientList from './components/IngredientList';
import Cart from './components/Cart';
import PaymentForm from './components/PaymentForm';
import './App.css';

const STEPS = ['Chat', 'Ingredients', 'Cart', 'Payment', 'Delivered'];
const SCREEN_TO_STEP = { chat: 0, ingredients: 1, cart: 2, payment: 3, success: 4 };

function ProgressBar({ screen }) {
  const current = SCREEN_TO_STEP[screen] ?? 0;
  return (
    <div className="progress-bar">
      {STEPS.map((label, i) => (
        <div key={i} className={`progress-step ${i <= current ? 'progress-active' : ''}`}>
          <div className="progress-dot">{i < current ? '✓' : i + 1}</div>
          <div className="progress-label">{label}</div>
          {i < STEPS.length - 1 && <div className={`progress-line ${i < current ? 'progress-line-active' : ''}`} />}
        </div>
      ))}
    </div>
  );
}

function App() {
  const [screen, setScreen] = useState('chat');
  const [ingredients, setIngredients] = useState([]);
  const [cart, setCart] = useState([]);
  const [budget, setBudget] = useState('mid-range');
  const [deliveryAddress, setDeliveryAddress] = useState('');

  const total = cart.reduce((sum, item) => sum + parseFloat(item.price), 0).toFixed(2);

  const handleIngredientsFound = (items) => {
    setIngredients(items);
    setScreen('ingredients');
  };

  const handleAddToCart = (items) => {
    setCart(items);
    setScreen('cart');
  };

  const handleRemove = (index) => {
    const updated = cart.filter((_, i) => i !== index);
    setCart(updated);
    if (updated.length === 0) setScreen('chat');
  };

  const handleRestart = () => {
    setCart([]);
    setIngredients([]);
    setScreen('chat');
  };

  return (
    <div className="app">
      <div className="header">
      <div className="brand">🛒 GroceryMind</div>
        {cart.length > 0 && screen !== 'success' && (
      <button className="cart-btn" onClick={() => setScreen('cart')}>
        Cart ({cart.length})
      </button>
      )}
    </div>

      <ProgressBar screen={screen} />

      {screen === 'chat' && (
        <ChatBox onIngredientsFound={handleIngredientsFound} />
      )}

      {screen === 'ingredients' && (
        <IngredientList
          ingredients={ingredients}
          onAddToCart={handleAddToCart}
          onBack={() => setScreen('chat')}
        />
      )}

      {screen === 'cart' && (
        <Cart
          cart={cart}
          onRemove={handleRemove}
          onCheckout={() => setScreen('payment')}
          onBack={() => setScreen('chat')}
        />
      )}

      {screen === 'payment' && (
        <PaymentForm
          total={total}
          onSuccess={(addr) => { setDeliveryAddress(addr); setScreen('success'); }}
          onBack={() => setScreen('cart')}
        />
      )}

      {screen === 'success' && (
        <div className="success">
          <div className="success-icon">🎉</div>
          <h2>Order confirmed!</h2>
          <div className="delivery-card">
            <div className="delivery-row">
              <span>📦</span>
              <div>
                <div className="delivery-label">Status</div>
                <div className="delivery-value">Order received & being packed</div>
              </div>
            </div>
            <div className="delivery-row">
              <span>🚚</span>
              <div>
                <div className="delivery-label">Estimated delivery</div>
                <div className="delivery-value">30–45 minutes to your door</div>
              </div>
            </div>
            <div className="delivery-row">
              <span>📍</span>
              <div>
                <div className="delivery-label">Delivering to</div>
                <div className="delivery-value">{deliveryAddress || 'Your address'}</div>
              </div>
            </div>
            <div className="delivery-row">
              <span>💳</span>
              <div>
                <div className="delivery-label">Payment</div>
                <div className="delivery-value">Confirmed ✓</div>
              </div>
            </div>
          </div>
          <p style={{ fontSize: 13, color: '#6B7280', marginBottom: 20 }}>
            You will receive a confirmation to your email shortly.
          </p>
          <button className="main-btn" onClick={handleRestart}>Start a new order</button>
        </div>
      )}
    </div>
  );
}

export default App;
